import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';
import { API_URL } from '../config';

const AddWorkout = () => {
  const { token } = useContext(AuthContext);
  const navigate = useNavigate();
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [exercise, setExercise] = useState('');
  const [sets, setSets] = useState([{ weight: '', reps: '' }]);
  const [notes, setNotes] = useState('');

  const handleSetChange = (index, field, value) => {
    const newSets = [...sets];
    newSets[index][field] = value;
    setSets(newSets);
  };

  const addSet = () => {
    setSets([...sets, { weight: '', reps: '' }]);
  };

  const removeSet = (index) => {
    if (sets.length > 1) {
      const newSets = sets.filter((_, i) => i !== index);
      setSets(newSets);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const validSets = sets.map(s => ({
      weight: parseFloat(s.weight) || 0,
      reps: parseInt(s.reps) || 0
    })).filter(s => s.weight > 0 && s.reps > 0);

    if (validSets.length === 0) {
      alert('Please add at least one valid set.');
      return;
    }

    const workoutData = { date, exercise, sets: validSets, notes };

    try {
      const res = await fetch(`${API_URL}/api/workouts`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-auth-token': token,
        },
        body: JSON.stringify(workoutData),
      });
      if (res.ok) {
        navigate('/');
      } else {
        alert('Failed to add workout');
      }
    } catch (err) {
      console.error(err);
      alert('Server error');
    }
  };

  return (
    <div className="form-container" style={{maxWidth: 600}}>
      <h2>Add Workout</h2>
      <form onSubmit={handleSubmit} style={{textAlign: 'left'}}>
        <label>Date:</label>
        <input type="date" value={date} onChange={(e) => setDate(e.target.value)} required />

        <label>Exercise:</label>
        <input type="text" placeholder="e.g. Bench Press" value={exercise} onChange={(e) => setExercise(e.target.value)} required />

        <label>Sets:</label>
        {sets.map((set, index) => (
          <div key={index} className="set-row">
            <input
              type="number"
              placeholder="Weight (kg)"
              value={set.weight}
              onChange={(e) => handleSetChange(index, 'weight', e.target.value)}
            />
            <input
              type="number"
              placeholder="Reps"
              value={set.reps}
              onChange={(e) => handleSetChange(index, 'reps', e.target.value)}
            />
            <button type="button" className="secondary" onClick={() => removeSet(index)}>-</button>
          </div>
        ))}
        <button type="button" className="secondary" style={{marginBottom: 20}} onClick={addSet}>+ Add Set</button>

        <label>Notes:</label>
        <textarea value={notes} onChange={(e) => setNotes(e.target.value)} rows="3" />

        <div style={{display: 'flex', gap: '10px', marginTop: '20px'}}>
          <button type="submit" style={{flex: 1}}>Save Workout</button>
          <button type="button" className="secondary" style={{flex: 1}} onClick={() => navigate('/')}>Cancel</button>
        </div>
      </form>
    </div>
  );
};

export default AddWorkout;
